import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"legal/privacy-policy.md","filePath":"legal/privacy-policy.md","lastUpdated":null}'),r={name:"legal/privacy-policy.md"};function n(s,e,l,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p><strong>Last Modified: [EFFECTIVE DATE]</strong></p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>Yumina LLC (&quot;Yumina,&quot; &quot;we,&quot; &quot;us,&quot; or &quot;our&quot;) is an AI interactive fiction and roleplay platform that enables users to create game worlds with characters, variables, rules, and interactive components; chat with AI-driven characters; and join multiplayer rooms. We are committed to protecting your privacy and handling your Personal Information responsibly.</p><p>This Privacy Policy (&quot;Policy&quot;) explains what Personal Information we collect, how we collect and use it, with whom we share it, and the rights and choices available to you. &quot;Personal Information&quot; means any information that identifies, relates to, describes, is reasonably capable of being associated with, or could reasonably be linked, directly or indirectly, to an identifiable individual.</p><p>By accessing or using the Yumina platform, website, and related services (collectively, the &quot;Service&quot;), you acknowledge that you have read and understood this Policy. If you do not agree with our practices, please do not use the Service.</p><hr><h2 id="_2-scope" tabindex="-1">2. Scope <a class="header-anchor" href="#_2-scope" aria-label="Permalink to &quot;2. Scope&quot;">​</a></h2><p>This Policy applies to the Yumina web platform and all related services operated by Yumina LLC, including:</p><ul><li>The Yumina website at [WEBSITE URL];</li><li>User account registration and management;</li><li>World creation, publishing, and discovery;</li><li>AI-powered chat and interactive fiction sessions;</li><li>Multiplayer rooms;</li><li>The Creator Rewards Program; and</li><li>Any other features, tools, or services we offer.</li></ul><p>This Policy does not apply to third-party websites, applications, or services that may be linked from or integrated with the Service. Please review the privacy policies of those third parties separately (see Section 20).</p><hr><h2 id="_3-age-policy" tabindex="-1">3. Age Policy <a class="header-anchor" href="#_3-age-policy" aria-label="Permalink to &quot;3. Age Policy&quot;">​</a></h2><p>The Service is intended for users who are at least <strong>13 years of age</strong>. We do not knowingly collect Personal Information from children under the age of 13. If we discover that we have collected Personal Information from a child under 13, we will promptly delete that information. Please see Section 19 (Children&#39;s Privacy) for additional detail.</p><p>Certain content on the Service is rated R-18 or R-18G and is restricted to users who are at least <strong>18 years of age</strong>. Access to age-restricted content requires self-declaration of your birth year and selection of the appropriate content level in your account settings. By enabling access to R-18 or R-18G content, you represent and warrant that you are at least 18 years old.</p><p>Content on the Service uses a tiered rating system, controlled by a single content level preference in your account settings:</p><ul><li><strong>All Ages</strong> -- Suitable for users aged 13 and older. (Default content level)</li><li><strong>R-18</strong> -- Restricted to users aged 18 and older.</li><li><strong>R-18G</strong> -- Restricted to users aged 18 and older; may contain graphic content. Setting your content level to R-18G also grants access to R-18 content.</li></ul><hr><h2 id="_4-contact-information" tabindex="-1">4. Contact Information <a class="header-anchor" href="#_4-contact-information" aria-label="Permalink to &quot;4. Contact Information&quot;">​</a></h2><p>If you have any questions, concerns, or requests regarding this Privacy Policy or our data practices, please contact us at:</p><p><strong>Yumina LLC</strong> [COMPANY ADDRESS] Email: [CONTACT EMAIL]</p><hr><h2 id="_5-personal-information-we-collect" tabindex="-1">5. Personal Information We Collect <a class="header-anchor" href="#_5-personal-information-we-collect" aria-label="Permalink to &quot;5. Personal Information We Collect&quot;">​</a></h2><p>We collect the following categories of Personal Information:</p><h3 id="_5-1-identity-data" tabindex="-1">5.1 Identity Data <a class="header-anchor" href="#_5-1-identity-data" aria-label="Permalink to &quot;5.1 Identity Data&quot;">​</a></h3><p>Information that identifies your account and person, including:</p><ul><li>Username</li><li>Email address</li><li>Password (stored as a cryptographic hash; we never store plaintext passwords)</li><li>Display name</li><li>Self-declared birth year</li></ul><h3 id="_5-2-device-and-network-data" tabindex="-1">5.2 Device and Network Data <a class="header-anchor" href="#_5-2-device-and-network-data" aria-label="Permalink to &quot;5.2 Device and Network Data&quot;">​</a></h3><p>Technical information collected when you access the Service, including:</p><ul><li>IP address</li><li>Browser type and version</li><li>Device type and operating system</li><li>Session identifiers and authentication tokens</li><li>Referring URLs and pages visited within the Service</li><li>Date, time, and duration of access</li></ul><h3 id="_5-3-user-content" tabindex="-1">5.3 User Content <a class="header-anchor" href="#_5-3-user-content" aria-label="Permalink to &quot;5.3 User Content&quot;">​</a></h3><p>Content you create, upload, or generate through the Service, including:</p><ul><li>Worlds (including characters, settings, variables, rules, game components, and first messages)</li><li>Chat messages exchanged during AI interactive fiction sessions</li><li>Uploaded images, avatars, and other media files</li><li>Multiplayer room configurations and in-room interactions</li><li>Comments, ratings, and other social interactions</li><li>AI-extracted narrative summaries (&quot;World Memories&quot;) automatically generated from your chat sessions, categorized by type (event, relationship, fact, decision, item, location, agreement, world state) and scored by narrative importance</li><li>Session checkpoints (snapshots of chat history and game state at specific points)</li><li>AI-assisted world-building conversations and proposals (&quot;Studio&quot; sessions)</li><li>Custom prompt templates and presets</li></ul><h3 id="_5-4-social-and-engagement-data" tabindex="-1">5.4 Social and Engagement Data <a class="header-anchor" href="#_5-4-social-and-engagement-data" aria-label="Permalink to &quot;5.4 Social and Engagement Data&quot;">​</a></h3><p>Data generated through your interactions with the community, including:</p><ul><li>Follow relationships (who you follow and who follows you)</li><li>Favorites (Worlds you have bookmarked)</li><li>Library metadata (Worlds in your library, last played time, update tracking)</li><li>Notifications and their read status</li><li>Achievement and milestone records</li></ul><p>&quot;User Content&quot; as used in this Policy refers collectively to all content you create or upload to the Service.</p><h3 id="_5-5-transaction-data" tabindex="-1">5.5 Transaction Data <a class="header-anchor" href="#_5-5-transaction-data" aria-label="Permalink to &quot;5.5 Transaction Data&quot;">​</a></h3><p>Records related to your financial transactions on the Service, including:</p><ul><li>Subscription status and plan details</li><li>Purchase history</li><li>Creator Rewards Program earnings and payout records</li><li>Tip and payment transaction records (amounts, dates, payer/payee associations)</li></ul><h3 id="_5-6-creator-tax-and-payout-data" tabindex="-1">5.6 Creator Tax and Payout Data <a class="header-anchor" href="#_5-6-creator-tax-and-payout-data" aria-label="Permalink to &quot;5.6 Creator Tax and Payout Data&quot;">​</a></h3><p>If you participate in the Creator Rewards Program, additional information is collected through Stripe Connect for payment and tax compliance purposes, including:</p><ul><li>Legal name (individual or business entity name)</li><li>Address (residential or business)</li><li>Tax identification information: Social Security Number (SSN) or Employer Identification Number (EIN) for U.S.-based Creators; equivalent tax identifiers for non-U.S. Creators</li><li>IRS Form W-8 data (W-8BEN or W-8BEN-E) for non-U.S. Creators, including country of tax residence and tax treaty claims</li><li>Bank account or debit card details for payout purposes</li><li>Date of birth (for identity verification)</li><li>Government-issued identification documents (if required by Stripe for identity verification)</li></ul><p><strong>This information is collected, stored, and managed by Stripe Connect, not by Yumina directly.</strong> Yumina may receive limited summary information from Stripe (e.g., payout status, tax form filing status, verification status) but does not store your full tax identification numbers or bank account details on Yumina&#39;s own systems. Please refer to <a href="https://stripe.com/privacy" target="_blank" rel="noreferrer">Stripe&#39;s Privacy Policy</a> for details on how Stripe handles this data.</p><h3 id="_5-7-financial-data" tabindex="-1">5.7 Financial Data <a class="header-anchor" href="#_5-7-financial-data" aria-label="Permalink to &quot;5.7 Financial Data&quot;">​</a></h3><p>Payment-related information required to process transactions. Yumina uses Stripe as its payment processor for both user purchases (subscriptions, credits) and Creator payouts (via Stripe Connect). <strong>Yumina does not directly store credit card numbers, debit card numbers, or full bank account details.</strong> Payment information is collected and processed by Stripe in accordance with <a href="https://stripe.com/privacy" target="_blank" rel="noreferrer">Stripe&#39;s Privacy Policy</a>. We may receive and store limited information from Stripe, such as the last four digits of your card, card brand, expiration date, and billing address.</p><h3 id="_5-8-audio-and-visual-data" tabindex="-1">5.8 Audio and Visual Data <a class="header-anchor" href="#_5-8-audio-and-visual-data" aria-label="Permalink to &quot;5.8 Audio and Visual Data&quot;">​</a></h3><p>Media you upload to the Service, including:</p><ul><li>Profile avatars</li><li>Character images and artwork</li><li>Other images or visual assets associated with your Worlds</li></ul><h3 id="_5-9-age-verification-data" tabindex="-1">5.9 Age Verification Data <a class="header-anchor" href="#_5-9-age-verification-data" aria-label="Permalink to &quot;5.9 Age Verification Data&quot;">​</a></h3><p>Information used to verify your age and control access to age-restricted content, including:</p><ul><li>Self-declared birth year</li><li>Content level preference (All Ages, R-18, or R-18G)</li></ul><h3 id="_5-10-third-party-login-data" tabindex="-1">5.10 Third-Party Login Data <a class="header-anchor" href="#_5-10-third-party-login-data" aria-label="Permalink to &quot;5.10 Third-Party Login Data&quot;">​</a></h3><p>If you register or sign in using a third-party authentication provider (Google, Discord, or X), we receive certain information from that provider as authorized by you during the OAuth process. This may include:</p><ul><li>Your name or display name on the third-party service</li><li>Email address associated with your third-party account</li><li>Profile picture or avatar</li><li>Unique account identifier from the third-party service</li></ul><p>We do not receive or store your passwords from third-party login providers.</p><hr><h2 id="_6-how-we-collect-personal-information" tabindex="-1">6. How We Collect Personal Information <a class="header-anchor" href="#_6-how-we-collect-personal-information" aria-label="Permalink to &quot;6. How We Collect Personal Information&quot;">​</a></h2><h3 id="_6-1-data-you-provide-directly" tabindex="-1">6.1 Data You Provide Directly <a class="header-anchor" href="#_6-1-data-you-provide-directly" aria-label="Permalink to &quot;6.1 Data You Provide Directly&quot;">​</a></h3><p>We collect Personal Information that you voluntarily provide when you:</p><ul><li><strong>Register for an account</strong> -- including your username, email address, password, display name, and birth year declaration.</li><li><strong>Create and publish content</strong> -- including Worlds, characters, variables, rules, components, images, and other creative assets.</li><li><strong>Use AI chat features</strong> -- including the chat messages you send during interactive fiction sessions.</li><li><strong>Participate in multiplayer rooms</strong> -- including room settings and in-room interactions.</li><li><strong>Manage your account settings</strong> -- including content rating preferences, profile information, and notification preferences.</li><li><strong>Contact us</strong> -- including any information you provide in support requests, feedback, or other communications.</li><li><strong>Participate in the Creator Rewards Program</strong> -- including identity verification, tax information (W-9 for U.S. Creators, W-8BEN/W-8BEN-E for non-U.S. Creators), and payout details, all collected through Stripe Connect.</li></ul><h3 id="_6-2-data-collected-automatically" tabindex="-1">6.2 Data Collected Automatically <a class="header-anchor" href="#_6-2-data-collected-automatically" aria-label="Permalink to &quot;6.2 Data Collected Automatically&quot;">​</a></h3><p>When you access or use the Service, we automatically collect certain information through cookies, server logs, and similar technologies, including:</p><ul><li>IP address and approximate geographic location</li><li>Browser type, version, and language settings</li><li>Device type, operating system, and screen resolution</li><li>Pages viewed, features used, and actions taken within the Service</li><li>Date, time, and duration of your visits</li><li>Referring and exit URLs</li><li>Session identifiers and authentication tokens</li></ul><p>Please see Section 10 (Cookies and Similar Technologies) for more information.</p><h3 id="_6-3-data-from-third-party-login-providers" tabindex="-1">6.3 Data from Third-Party Login Providers <a class="header-anchor" href="#_6-3-data-from-third-party-login-providers" aria-label="Permalink to &quot;6.3 Data from Third-Party Login Providers&quot;">​</a></h3><p>If you choose to register or sign in using Google, Discord, or X (formerly Twitter), we receive the information described in Section 5.10 through the OAuth authentication process. The information we receive depends on your privacy settings with the third-party provider and the permissions you grant during the authentication flow.</p><hr><h2 id="_7-how-we-use-personal-information" tabindex="-1">7. How We Use Personal Information <a class="header-anchor" href="#_7-how-we-use-personal-information" aria-label="Permalink to &quot;7. How We Use Personal Information&quot;">​</a></h2><p>We use the Personal Information we collect for the following purposes:</p><h3 id="_7-1-service-operation" tabindex="-1">7.1 Service Operation <a class="header-anchor" href="#_7-1-service-operation" aria-label="Permalink to &quot;7.1 Service Operation&quot;">​</a></h3><ul><li>Creating and managing your account</li><li>Displaying your published Worlds and content to other users in accordance with your settings</li><li>Processing AI chat interactions (sending your messages to third-party AI service providers and returning generated responses)</li><li>Facilitating multiplayer rooms and real-time interactions</li><li>Processing transactions, subscriptions, and Creator rewards payouts</li></ul><h3 id="_7-2-age-verification-and-content-gating" tabindex="-1">7.2 Age Verification and Content Gating <a class="header-anchor" href="#_7-2-age-verification-and-content-gating" aria-label="Permalink to &quot;7.2 Age Verification and Content Gating&quot;">​</a></h3><ul><li>Verifying that you meet the minimum age requirement (13+) to use the Service based on your declared birth year</li><li>Restricting access to R-18 and R-18G content to users who are at least 18 years old based on their declared birth year and content level preference</li><li>Enforcing content rating classifications</li></ul><h3 id="_7-3-content-moderation-and-safety" tabindex="-1">7.3 Content Moderation and Safety <a class="header-anchor" href="#_7-3-content-moderation-and-safety" aria-label="Permalink to &quot;7.3 Content Moderation and Safety&quot;">​</a></h3><ul><li>Monitoring for violations of our terms of service and community guidelines</li><li>Reviewing reported content and user behavior</li><li>Protecting the safety of our users and the integrity of the Service</li></ul><h3 id="_7-4-security-and-fraud-prevention" tabindex="-1">7.4 Security and Fraud Prevention <a class="header-anchor" href="#_7-4-security-and-fraud-prevention" aria-label="Permalink to &quot;7.4 Security and Fraud Prevention&quot;">​</a></h3><ul><li>Detecting, investigating, and preventing unauthorized access, fraud, and other malicious activity</li><li>Protecting the security and integrity of the Service and its infrastructure</li><li>Verifying user identity when necessary</li></ul><h3 id="_7-5-analytics" tabindex="-1">7.5 Analytics <a class="header-anchor" href="#_7-5-analytics" aria-label="Permalink to &quot;7.5 Analytics&quot;">​</a></h3><ul><li>Analyzing aggregate, non-individually-identifiable usage data to understand how the Service is used</li><li>Identifying trends and areas for improvement</li><li>Measuring the performance and reliability of the Service</li></ul><p>We use aggregate analytics -- not individual-level tracking -- to improve the Service.</p><h3 id="_7-6-communications" tabindex="-1">7.6 Communications <a class="header-anchor" href="#_7-6-communications" aria-label="Permalink to &quot;7.6 Communications&quot;">​</a></h3><ul><li>Sending service-related notifications (e.g., account verification, security alerts, system updates)</li><li>Sending marketing or promotional communications (with your consent where required, and always with the ability to opt out)</li><li>Responding to your inquiries and support requests</li></ul><h3 id="_7-7-legal-compliance" tabindex="-1">7.7 Legal Compliance <a class="header-anchor" href="#_7-7-legal-compliance" aria-label="Permalink to &quot;7.7 Legal Compliance&quot;">​</a></h3><ul><li>Complying with applicable laws, regulations, and legal processes</li><li>Enforcing our terms of service and other agreements</li><li>Establishing, exercising, or defending legal claims</li></ul><h3 id="_7-8-statement-regarding-ai-model-training" tabindex="-1">7.8 Statement Regarding AI Model Training <a class="header-anchor" href="#_7-8-statement-regarding-ai-model-training" aria-label="Permalink to &quot;7.8 Statement Regarding AI Model Training&quot;">​</a></h3><p><strong>Yumina does not use your User Content to train AI models.</strong> See Section 8.2 for additional detail.</p><hr><h2 id="_8-ai-chat-data-processing" tabindex="-1">8. AI Chat Data Processing <a class="header-anchor" href="#_8-ai-chat-data-processing" aria-label="Permalink to &quot;8. AI Chat Data Processing&quot;">​</a></h2><p>This section explains how your data is handled when you use the AI chat features of the Service.</p><h3 id="_8-1-how-ai-chat-works" tabindex="-1">8.1 How AI Chat Works <a class="header-anchor" href="#_8-1-how-ai-chat-works" aria-label="Permalink to &quot;8.1 How AI Chat Works&quot;">​</a></h3><p>When you engage in an AI interactive fiction or chat session, your chat messages -- along with relevant context from your World (such as character descriptions, system prompts, variables, and rules) -- are sent to <strong>third-party AI service providers</strong> to generate responses. This transmission is necessary for the Service to function.</p><h3 id="_8-2-yumina-does-not-train-on-your-content" tabindex="-1">8.2 Yumina Does Not Train on Your Content <a class="header-anchor" href="#_8-2-yumina-does-not-train-on-your-content" aria-label="Permalink to &quot;8.2 Yumina Does Not Train on Your Content&quot;">​</a></h3><p>Yumina does not use your chat messages, World content, or any other User Content to train, fine-tune, or improve any AI model. Your content is used solely to provide the Service to you.</p><h3 id="_8-3-third-party-ai-provider-policies" tabindex="-1">8.3 Third-Party AI Provider Policies <a class="header-anchor" href="#_8-3-third-party-ai-provider-policies" aria-label="Permalink to &quot;8.3 Third-Party AI Provider Policies&quot;">​</a></h3><p>The third-party AI service providers currently used by the Service include OpenRouter, Anthropic, and OpenAI. A current list of providers is maintained at [AI PROVIDERS URL]. Each provider has its own privacy policies and data handling practices. Yumina selects providers that offer API terms under which user inputs submitted via the API are not used for model training, where such terms are available. However, Yumina cannot guarantee the data practices of third-party providers, and their policies may change.</p><p>The Service also supports Ollama for local inference. When Ollama is configured, AI processing occurs entirely on your own device and your data is not transmitted to any third-party AI provider.</p><h3 id="_8-4-sensitive-information-in-chat" tabindex="-1">8.4 Sensitive Information in Chat <a class="header-anchor" href="#_8-4-sensitive-information-in-chat" aria-label="Permalink to &quot;8.4 Sensitive Information in Chat&quot;">​</a></h3><p>You should <strong>avoid entering real, sensitive personal information</strong> (such as real names, addresses, phone numbers, financial account numbers, Social Security numbers, or health information) in AI chat sessions. While Yumina takes steps to protect your data, chat messages are transmitted to third-party AI service providers for processing, and the interactive fiction environment is not designed for the handling of real-world sensitive personal data.</p><hr><h2 id="_9-data-sharing" tabindex="-1">9. Data Sharing <a class="header-anchor" href="#_9-data-sharing" aria-label="Permalink to &quot;9. Data Sharing&quot;">​</a></h2><p>We share Personal Information only as described below. <strong>We do not sell your Personal Information.</strong></p><h3 id="_9-1-service-providers" tabindex="-1">9.1 Service Providers <a class="header-anchor" href="#_9-1-service-providers" aria-label="Permalink to &quot;9.1 Service Providers&quot;">​</a></h3><p>We share Personal Information with trusted third-party service providers who assist us in operating the Service, including:</p><ul><li><strong>Hosting and infrastructure providers</strong> that store and serve the Service, including cloud storage providers (such as S3-compatible object storage) used to store user-uploaded assets (images, audio, and other media files)</li><li><strong>Payment processors</strong> — Stripe processes user purchases (subscriptions, credits) and, through Stripe Connect, processes Creator Rewards payouts, identity verification, and tax reporting (including 1099-NEC issuance for U.S. Creators and W-8 form collection for non-U.S. Creators)</li><li><strong>Third-party AI service providers</strong> that generate AI chat responses (currently OpenRouter, Anthropic, and OpenAI; see Section 8)</li><li><strong>[ANALYTICS PROVIDERS]</strong> [TBD -- analytics tools not yet decided]</li></ul><p>These service providers are contractually obligated to use your Personal Information only to provide services to us and in accordance with this Policy. For payment and tax processing, Stripe acts as a data processor and, in some cases, an independent data controller — please review <a href="https://stripe.com/privacy" target="_blank" rel="noreferrer">Stripe&#39;s Privacy Policy</a> for details on their data practices.</p><h3 id="_9-2-other-users" tabindex="-1">9.2 Other Users <a class="header-anchor" href="#_9-2-other-users" aria-label="Permalink to &quot;9.2 Other Users&quot;">​</a></h3><p>When you publish a World, the content you designate as public (including the World&#39;s title, description, characters, tags, and associated images) becomes visible to other users of the Service in accordance with your publication settings. Your username and display name are associated with your published Worlds. Unpublished Worlds and private content are not shared with other users.</p><h3 id="_9-3-legal-disclosures" tabindex="-1">9.3 Legal Disclosures <a class="header-anchor" href="#_9-3-legal-disclosures" aria-label="Permalink to &quot;9.3 Legal Disclosures&quot;">​</a></h3><p>We may disclose Personal Information if we believe in good faith that such disclosure is necessary to:</p><ul><li>Comply with applicable law, regulation, legal process, or governmental request</li><li>Enforce our terms of service or other agreements</li><li>Protect the rights, property, or safety of Yumina, our users, or the public</li><li>Detect, prevent, or address fraud, security issues, or technical problems</li></ul><h3 id="_9-4-corporate-events" tabindex="-1">9.4 Corporate Events <a class="header-anchor" href="#_9-4-corporate-events" aria-label="Permalink to &quot;9.4 Corporate Events&quot;">​</a></h3><p>In the event of a merger, acquisition, reorganization, bankruptcy, asset sale, or similar corporate transaction, your Personal Information may be transferred to the acquiring or successor entity. We will provide notice before your Personal Information is transferred and becomes subject to a different privacy policy.</p><h3 id="_9-5-no-sale-of-personal-data" tabindex="-1">9.5 No Sale of Personal Data <a class="header-anchor" href="#_9-5-no-sale-of-personal-data" aria-label="Permalink to &quot;9.5 No Sale of Personal Data&quot;">​</a></h3><p><strong>Yumina does not sell, rent, or lease your Personal Information to third parties.</strong> We do not share your Personal Information with third parties for their own direct marketing purposes.</p><hr><h2 id="_10-cookies-and-similar-technologies" tabindex="-1">10. Cookies and Similar Technologies <a class="header-anchor" href="#_10-cookies-and-similar-technologies" aria-label="Permalink to &quot;10. Cookies and Similar Technologies&quot;">​</a></h2><h3 id="_10-1-what-are-cookies" tabindex="-1">10.1 What Are Cookies <a class="header-anchor" href="#_10-1-what-are-cookies" aria-label="Permalink to &quot;10.1 What Are Cookies&quot;">​</a></h3><p>Cookies are small text files placed on your device by a website. They are widely used to make websites work efficiently and to provide information to the operators of the site. We may also use similar technologies such as local storage and session storage.</p><h3 id="_10-2-cookies-we-use" tabindex="-1">10.2 Cookies We Use <a class="header-anchor" href="#_10-2-cookies-we-use" aria-label="Permalink to &quot;10.2 Cookies We Use&quot;">​</a></h3><ul><li><strong>Essential Cookies</strong> -- Required for the Service to function. These cookies enable core features such as user authentication, session management, and security. You cannot opt out of essential cookies without losing the ability to use the Service.</li><li><strong>Functional Cookies</strong> -- Used to remember your preferences and settings, including content level preference (All Ages, R-18, or R-18G), display preferences, and other personalization choices.</li><li><strong>Analytics Cookies</strong> -- Used to collect aggregate information about how users interact with the Service, helping us understand usage patterns and improve the Service. These cookies do not identify individual users. [ANALYTICS PROVIDERS]</li></ul><h3 id="_10-3-managing-cookies" tabindex="-1">10.3 Managing Cookies <a class="header-anchor" href="#_10-3-managing-cookies" aria-label="Permalink to &quot;10.3 Managing Cookies&quot;">​</a></h3><p>Most web browsers allow you to control cookies through their settings. You can typically set your browser to:</p><ul><li>Block all cookies</li><li>Accept only first-party cookies</li><li>Delete cookies when you close your browser</li><li>Be notified when a cookie is set</li></ul><p>Please note that blocking or deleting essential cookies may prevent you from using the Service or cause it to function improperly. For more information about managing cookies, visit your browser&#39;s help documentation.</p><hr><h2 id="_11-data-storage-and-security" tabindex="-1">11. Data Storage and Security <a class="header-anchor" href="#_11-data-storage-and-security" aria-label="Permalink to &quot;11. Data Storage and Security&quot;">​</a></h2><h3 id="_11-1-data-location" tabindex="-1">11.1 Data Location <a class="header-anchor" href="#_11-1-data-location" aria-label="Permalink to &quot;11.1 Data Location&quot;">​</a></h3><p>Your Personal Information is stored and processed in the <strong>United States</strong>. By using the Service, you consent to the transfer and storage of your data in the United States. Please see Section 17 (International Users) for additional information.</p><h3 id="_11-2-security-measures" tabindex="-1">11.2 Security Measures <a class="header-anchor" href="#_11-2-security-measures" aria-label="Permalink to &quot;11.2 Security Measures&quot;">​</a></h3><p>We implement industry-standard technical and organizational measures to protect your Personal Information, including:</p><ul><li><strong>Encryption in transit</strong> -- All data transmitted between your device and the Service is encrypted using HTTPS/TLS.</li><li><strong>Encryption at rest</strong> -- Sensitive data, such as API keys, is encrypted using AES-256-GCM.</li><li><strong>Password hashing</strong> -- User passwords are stored as cryptographic hashes; plaintext passwords are never stored.</li><li><strong>Access controls</strong> -- Access to Personal Information is restricted to authorized personnel on a need-to-know basis.</li><li><strong>Regular security reviews</strong> -- We periodically review and update our security practices.</li></ul><h3 id="_11-3-no-absolute-guarantee" tabindex="-1">11.3 No Absolute Guarantee <a class="header-anchor" href="#_11-3-no-absolute-guarantee" aria-label="Permalink to &quot;11.3 No Absolute Guarantee&quot;">​</a></h3><p>While we take reasonable steps to protect your Personal Information, no method of transmission over the Internet and no method of electronic storage is completely secure. We cannot guarantee the absolute security of your data. You use the Service at your own risk with respect to security.</p><hr><h2 id="_12-data-retention" tabindex="-1">12. Data Retention <a class="header-anchor" href="#_12-data-retention" aria-label="Permalink to &quot;12. Data Retention&quot;">​</a></h2><h3 id="_12-1-active-accounts" tabindex="-1">12.1 Active Accounts <a class="header-anchor" href="#_12-1-active-accounts" aria-label="Permalink to &quot;12.1 Active Accounts&quot;">​</a></h3><p>We retain your Personal Information for as long as your account remains active and as needed to provide the Service to you. The following retention periods apply to specific data categories for active accounts:</p><table tabindex="0"><thead><tr><th>Data Category</th><th>Retention Period</th></tr></thead><tbody><tr><td>Chat messages and session data</td><td>Duration of account</td></tr><tr><td>World Memories (AI-extracted summaries)</td><td>Duration of account (max 100 per World)</td></tr><tr><td>Server access logs (IP, user agent)</td><td>90 days</td></tr><tr><td>Security event logs</td><td>1 year</td></tr><tr><td>Payment and transaction records</td><td>7 years (tax and regulatory compliance)</td></tr><tr><td>Aggregate analytics data (de-identified)</td><td>Indefinite</td></tr></tbody></table><h3 id="_12-2-deleted-accounts" tabindex="-1">12.2 Deleted Accounts <a class="header-anchor" href="#_12-2-deleted-accounts" aria-label="Permalink to &quot;12.2 Deleted Accounts&quot;">​</a></h3><p>When you close or delete your account, we will delete your Personal Information within <strong>7 days</strong> of account closure. This includes your Identity Data, User Content, and other Personal Information associated with your account.</p><h3 id="_12-3-legal-exceptions" tabindex="-1">12.3 Legal Exceptions <a class="header-anchor" href="#_12-3-legal-exceptions" aria-label="Permalink to &quot;12.3 Legal Exceptions&quot;">​</a></h3><p>Notwithstanding the above, we may retain certain Personal Information for longer periods where required or permitted by applicable law, including for:</p><ul><li>Compliance with legal, regulatory, tax, or accounting obligations</li><li>Resolution of disputes</li><li>Enforcement of our agreements</li><li>Fraud prevention and security purposes</li></ul><h3 id="_12-4-periodic-review" tabindex="-1">12.4 Periodic Review <a class="header-anchor" href="#_12-4-periodic-review" aria-label="Permalink to &quot;12.4 Periodic Review&quot;">​</a></h3><p>We periodically review our data retention practices to ensure that Personal Information is not retained longer than necessary for the purposes described in this Policy.</p><hr><h2 id="_13-data-breach-notification" tabindex="-1">13. Data Breach Notification <a class="header-anchor" href="#_13-data-breach-notification" aria-label="Permalink to &quot;13. Data Breach Notification&quot;">​</a></h2><p>In the event of a data breach that affects your Personal Information:</p><ul><li>We will notify affected users <strong>within 72 hours</strong> of confirming the breach, providing information about what happened, what data was affected, and what steps we are taking in response.</li><li>We will notify relevant <strong>regulatory authorities</strong> as required by applicable law, including within 72 hours for GDPR supervisory authorities where applicable.</li><li>We will take prompt action to contain the breach and mitigate any harm.</li></ul><hr><h2 id="_14-your-rights-and-choices" tabindex="-1">14. Your Rights and Choices <a class="header-anchor" href="#_14-your-rights-and-choices" aria-label="Permalink to &quot;14. Your Rights and Choices&quot;">​</a></h2><p>Depending on your jurisdiction, you may have the following rights regarding your Personal Information:</p><h3 id="_14-1-right-to-access" tabindex="-1">14.1 Right to Access <a class="header-anchor" href="#_14-1-right-to-access" aria-label="Permalink to &quot;14.1 Right to Access&quot;">​</a></h3><p>You have the right to request a copy of the Personal Information we hold about you. You can view much of your Personal Information directly through your account settings.</p><h3 id="_14-2-right-to-correction" tabindex="-1">14.2 Right to Correction <a class="header-anchor" href="#_14-2-right-to-correction" aria-label="Permalink to &quot;14.2 Right to Correction&quot;">​</a></h3><p>You have the right to request correction of inaccurate or incomplete Personal Information. You can update most of your account information directly through your account settings.</p><h3 id="_14-3-right-to-deletion" tabindex="-1">14.3 Right to Deletion <a class="header-anchor" href="#_14-3-right-to-deletion" aria-label="Permalink to &quot;14.3 Right to Deletion&quot;">​</a></h3><p>You have the right to request deletion of your Personal Information. You can delete your account through your account settings, and your data will be deleted within 7 days. Certain data may be retained as described in Section 12.3.</p><h3 id="_14-4-right-to-export" tabindex="-1">14.4 Right to Export <a class="header-anchor" href="#_14-4-right-to-export" aria-label="Permalink to &quot;14.4 Right to Export&quot;">​</a></h3><p>You have the right to export your data in a portable format. Yumina provides the ability to export your Worlds and chat history through the Service.</p><h3 id="_14-5-right-to-withdraw-consent" tabindex="-1">14.5 Right to Withdraw Consent <a class="header-anchor" href="#_14-5-right-to-withdraw-consent" aria-label="Permalink to &quot;14.5 Right to Withdraw Consent&quot;">​</a></h3><p>Where we rely on your consent to process Personal Information, you have the right to withdraw that consent at any time. Withdrawing consent does not affect the lawfulness of processing that occurred before the withdrawal. Please note that if your consent is necessary for the provision of the Service, withdrawing consent may require you to close your account.</p><h3 id="_14-6-marketing-opt-out" tabindex="-1">14.6 Marketing Opt-Out <a class="header-anchor" href="#_14-6-marketing-opt-out" aria-label="Permalink to &quot;14.6 Marketing Opt-Out&quot;">​</a></h3><p>You can opt out of receiving marketing and promotional communications from us by:</p><ul><li>Clicking the &quot;unsubscribe&quot; link in any marketing email we send</li><li>Adjusting your notification preferences in your account settings</li><li>Contacting us at [CONTACT EMAIL]</li></ul><p>Opting out of marketing communications does not affect service-related communications (such as security alerts and account notifications).</p><h3 id="_14-7-cookie-controls" tabindex="-1">14.7 Cookie Controls <a class="header-anchor" href="#_14-7-cookie-controls" aria-label="Permalink to &quot;14.7 Cookie Controls&quot;">​</a></h3><p>You can manage cookies through your browser settings as described in Section 10.3.</p><h3 id="_14-8-how-to-exercise-your-rights" tabindex="-1">14.8 How to Exercise Your Rights <a class="header-anchor" href="#_14-8-how-to-exercise-your-rights" aria-label="Permalink to &quot;14.8 How to Exercise Your Rights&quot;">​</a></h3><p>To exercise any of the rights described above, please contact us at [CONTACT EMAIL]. We may need to verify your identity before processing your request. We will respond to your request within a reasonable timeframe and in accordance with applicable law.</p><hr><h2 id="_15-california-privacy-rights-ccpa-cpra" tabindex="-1">15. California Privacy Rights (CCPA/CPRA) <a class="header-anchor" href="#_15-california-privacy-rights-ccpa-cpra" aria-label="Permalink to &quot;15. California Privacy Rights (CCPA/CPRA)&quot;">​</a></h2><p>If you are a California resident, the California Consumer Privacy Act (CCPA), as amended by the California Privacy Rights Act (CPRA), provides you with additional rights regarding your Personal Information.</p><h3 id="_15-1-right-to-know" tabindex="-1">15.1 Right to Know <a class="header-anchor" href="#_15-1-right-to-know" aria-label="Permalink to &quot;15.1 Right to Know&quot;">​</a></h3><p>You have the right to request that we disclose:</p><ul><li>The categories of Personal Information we have collected about you</li><li>The categories of sources from which we collected your Personal Information</li><li>The business or commercial purpose for collecting your Personal Information</li><li>The categories of third parties with whom we share your Personal Information</li><li>The specific pieces of Personal Information we have collected about you</li></ul><h3 id="_15-2-right-to-delete" tabindex="-1">15.2 Right to Delete <a class="header-anchor" href="#_15-2-right-to-delete" aria-label="Permalink to &quot;15.2 Right to Delete&quot;">​</a></h3><p>You have the right to request that we delete Personal Information we have collected from you, subject to certain exceptions permitted by law.</p><h3 id="_15-3-right-to-opt-out-of-sale" tabindex="-1">15.3 Right to Opt-Out of Sale <a class="header-anchor" href="#_15-3-right-to-opt-out-of-sale" aria-label="Permalink to &quot;15.3 Right to Opt-Out of Sale&quot;">​</a></h3><p><strong>We do not sell your Personal Information.</strong> However, you have the right to direct a business that sells your Personal Information to stop doing so. Because we do not engage in the sale of Personal Information, no opt-out mechanism is necessary, but we honor this right as a matter of principle.</p><h3 id="_15-4-right-to-non-discrimination" tabindex="-1">15.4 Right to Non-Discrimination <a class="header-anchor" href="#_15-4-right-to-non-discrimination" aria-label="Permalink to &quot;15.4 Right to Non-Discrimination&quot;">​</a></h3><p>We will not discriminate against you for exercising any of your privacy rights under the CCPA/CPRA. We will not:</p><ul><li>Deny you the Service</li><li>Charge you different prices or rates</li><li>Provide you a different level or quality of service</li><li>Suggest any of the above will occur as a result of exercising your rights</li></ul><h3 id="_15-5-other-u-s-state-privacy-rights" tabindex="-1">15.5 Other U.S. State Privacy Rights <a class="header-anchor" href="#_15-5-other-u-s-state-privacy-rights" aria-label="Permalink to &quot;15.5 Other U.S. State Privacy Rights&quot;">​</a></h3><p>Residents of Virginia (VCDPA), Colorado (CPA), Connecticut (CTDPA), Utah (UCPA), Nevada (NRS Chapter 603A), and other states with consumer data privacy laws may have rights similar to those described above, including the right to access, correct, delete, and opt out of the sale of certain personal information. We do not sell your Personal Information under any state law definition.</p><h3 id="_15-6-submitting-requests" tabindex="-1">15.6 Submitting Requests <a class="header-anchor" href="#_15-6-submitting-requests" aria-label="Permalink to &quot;15.6 Submitting Requests&quot;">​</a></h3><p>To submit a request under the CCPA/CPRA or other applicable U.S. state privacy laws, please contact us at [CONTACT EMAIL]. We will verify your identity before processing your request and will respond within the timeframe required by applicable law (45 days for CCPA/CPRA). You may also designate an authorized agent to make a request on your behalf, subject to verification.</p><hr><h2 id="_16-european-economic-area-united-kingdom-and-swiss-users" tabindex="-1">16. European Economic Area, United Kingdom, and Swiss Users <a class="header-anchor" href="#_16-european-economic-area-united-kingdom-and-swiss-users" aria-label="Permalink to &quot;16. European Economic Area, United Kingdom, and Swiss Users&quot;">​</a></h2><p>If you are located in the European Economic Area (&quot;EEA&quot;), the United Kingdom (&quot;UK&quot;), or Switzerland, the following additional provisions apply to you under the General Data Protection Regulation (&quot;GDPR&quot;), the UK GDPR, and the Swiss Federal Act on Data Protection (&quot;FADP&quot;), respectively.</p><h3 id="_16-1-legal-basis-for-processing" tabindex="-1">16.1 Legal Basis for Processing <a class="header-anchor" href="#_16-1-legal-basis-for-processing" aria-label="Permalink to &quot;16.1 Legal Basis for Processing&quot;">​</a></h3><p>We process your Personal Information on the following legal bases:</p><ul><li><strong>Contract Performance (Article 6(1)(b) GDPR):</strong> Processing necessary to provide the Service to you, including account creation, chat processing, session management, and payment processing.</li><li><strong>Legitimate Interests (Article 6(1)(f) GDPR):</strong> Processing necessary for our legitimate interests, including platform security, fraud prevention, aggregate analytics, and service improvement, where those interests are not overridden by your data protection rights.</li><li><strong>Consent (Article 6(1)(a) GDPR):</strong> Processing based on your consent, including access to R-18/R-18G content, marketing communications, and optional cookies. You may withdraw consent at any time (see Section 14.5).</li><li><strong>Legal Obligation (Article 6(1)(c) GDPR):</strong> Processing necessary to comply with legal obligations, including tax reporting, law enforcement requests, and regulatory requirements.</li></ul><h3 id="_16-2-data-protection-officer" tabindex="-1">16.2 Data Protection Officer <a class="header-anchor" href="#_16-2-data-protection-officer" aria-label="Permalink to &quot;16.2 Data Protection Officer&quot;">​</a></h3><p>[DPO DESIGNATION OR STATEMENT — e.g., &quot;Yumina has not designated a Data Protection Officer as it does not meet the threshold requirements under Article 37 GDPR. For data protection inquiries, please contact us at [CONTACT EMAIL].&quot;]</p><h3 id="_16-3-cross-border-data-transfers" tabindex="-1">16.3 Cross-Border Data Transfers <a class="header-anchor" href="#_16-3-cross-border-data-transfers" aria-label="Permalink to &quot;16.3 Cross-Border Data Transfers&quot;">​</a></h3><p>Your Personal Information is transferred to and processed in the United States. We rely on the following transfer mechanisms to ensure adequate protection of your data:</p><ul><li><strong>Standard Contractual Clauses (SCCs)</strong> as adopted by the European Commission (Commission Implementing Decision (EU) 2021/914), executed with our service providers.</li><li>Where applicable, supplementary measures including encryption in transit and at rest.</li></ul><h3 id="_16-4-additional-rights" tabindex="-1">16.4 Additional Rights <a class="header-anchor" href="#_16-4-additional-rights" aria-label="Permalink to &quot;16.4 Additional Rights&quot;">​</a></h3><p>In addition to the rights described in Section 14, EEA, UK, and Swiss users have the following rights:</p><ul><li><strong>Right to Data Portability:</strong> You have the right to receive your Personal Information in a structured, commonly used, and machine-readable format, and to transmit that data to another controller.</li><li><strong>Right to Restriction of Processing:</strong> You have the right to request restriction of processing of your Personal Information in certain circumstances (e.g., while we verify accuracy after a correction request).</li><li><strong>Right to Object:</strong> You have the right to object to processing of your Personal Information based on legitimate interests. We will cease processing unless we demonstrate compelling legitimate grounds.</li><li><strong>Right to Lodge a Complaint:</strong> You have the right to lodge a complaint with your local supervisory authority if you believe our processing of your Personal Information violates applicable data protection law. A list of EEA supervisory authorities is available at <a href="https://edpb.europa.eu/about-edpb/about-edpb/members_en" target="_blank" rel="noreferrer">https://edpb.europa.eu/about-edpb/about-edpb/members_en</a>.</li></ul><h3 id="_16-5-data-breach-notification" tabindex="-1">16.5 Data Breach Notification <a class="header-anchor" href="#_16-5-data-breach-notification" aria-label="Permalink to &quot;16.5 Data Breach Notification&quot;">​</a></h3><p>In the event of a personal data breach likely to result in a risk to your rights and freedoms, we will notify the relevant supervisory authority within 72 hours of becoming aware of the breach, as required by Article 33 GDPR. Where the breach is likely to result in a high risk to your rights and freedoms, we will also notify you directly without undue delay, as required by Article 34 GDPR.</p><h3 id="_16-6-automated-decision-making" tabindex="-1">16.6 Automated Decision-Making <a class="header-anchor" href="#_16-6-automated-decision-making" aria-label="Permalink to &quot;16.6 Automated Decision-Making&quot;">​</a></h3><p>Yumina does not engage in automated decision-making or profiling that produces legal effects or similarly significantly affects you, as described in Article 22 GDPR. Content recommendations on the Service are based on aggregate engagement data and do not constitute profiling with legal or similarly significant effects.</p><hr><h2 id="_17-international-users-all-other-jurisdictions" tabindex="-1">17. International Users (All Other Jurisdictions) <a class="header-anchor" href="#_17-international-users-all-other-jurisdictions" aria-label="Permalink to &quot;17. International Users (All Other Jurisdictions)&quot;">​</a></h2><p>The Service is operated from and data is stored in the <strong>United States</strong>. If you are accessing the Service from outside the United States, please be aware that your Personal Information will be transferred to, stored in, and processed in the United States.</p><p>By using the Service, you consent to the transfer of your Personal Information to the United States. The data protection and privacy laws of the United States may differ from, and may not provide the same level of protection as, the laws in your country of residence. You acknowledge and accept these risks by using the Service. For users in the EEA, UK, and Switzerland, please refer to Section 16 for applicable transfer mechanisms and additional rights.</p><hr><h2 id="_18-do-not-track-signals" tabindex="-1">18. &quot;Do Not Track&quot; Signals <a class="header-anchor" href="#_18-do-not-track-signals" aria-label="Permalink to &quot;18. &quot;Do Not Track&quot; Signals&quot;">​</a></h2><p>The Service does not currently respond to &quot;Do Not Track&quot; (DNT) browser signals or similar mechanisms.</p><hr><h2 id="_19-children-s-privacy-coppa" tabindex="-1">19. Children&#39;s Privacy (COPPA) <a class="header-anchor" href="#_19-children-s-privacy-coppa" aria-label="Permalink to &quot;19. Children&#39;s Privacy (COPPA)&quot;">​</a></h2><p>The Service is not directed to children under the age of 13. We do not knowingly collect, use, or disclose Personal Information from children under 13 years of age, in compliance with the Children&#39;s Online Privacy Protection Act (COPPA).</p><p>If you are under 13 years of age, <strong>do not use the Service</strong> and do not provide any Personal Information to us. Do not create an account, submit any content, or enter any information on the Service.</p><p>If we learn that we have collected Personal Information from a child under 13, we will take prompt steps to delete that information and terminate the associated account. If you are a parent or guardian and believe that your child under 13 has provided Personal Information to us, please contact us immediately at [CONTACT EMAIL] so that we can take appropriate action.</p><hr><h2 id="_20-third-party-links" tabindex="-1">20. Third-Party Links <a class="header-anchor" href="#_20-third-party-links" aria-label="Permalink to &quot;20. Third-Party Links&quot;">​</a></h2><p>The Service may contain links to third-party websites, applications, or services that are not operated or controlled by Yumina. This includes, but is not limited to, third-party authentication providers (Google, Discord, X) and external websites linked from User Content.</p><p>This Policy does not apply to any third-party websites, applications, or services. We are not responsible for the privacy practices, content, or security of any third party. We encourage you to review the privacy policies of any third-party services you access through or in connection with the Service.</p><hr><h2 id="_21-changes-to-this-policy" tabindex="-1">21. Changes to This Policy <a class="header-anchor" href="#_21-changes-to-this-policy" aria-label="Permalink to &quot;21. Changes to This Policy&quot;">​</a></h2><p>We may update this Privacy Policy from time to time to reflect changes in our practices, the Service, or applicable law. When we make changes:</p><ul><li>We will update the &quot;Last Modified&quot; date at the top of this Policy.</li><li>For <strong>material changes</strong>, we will notify you by email (sent to the email address associated with your account) and/or by prominent notice within the Service (such as an in-app notification or banner).</li><li>We encourage you to review this Policy periodically.</li></ul><p>Your continued use of the Service after the effective date of any updated Policy constitutes your acceptance of the changes. If you do not agree with the updated Policy, you should stop using the Service and delete your account.</p><hr><h2 id="_22-contact-us" tabindex="-1">22. Contact Us <a class="header-anchor" href="#_22-contact-us" aria-label="Permalink to &quot;22. Contact Us&quot;">​</a></h2><p>If you have any questions, concerns, or requests regarding this Privacy Policy or our privacy practices, please contact us:</p><p><strong>Yumina LLC</strong> [COMPANY ADDRESS]</p><p><strong>Email:</strong> [CONTACT EMAIL]</p><p><strong>Security vulnerabilities:</strong> [SECURITY EMAIL]</p><p><strong>Website:</strong> [WEBSITE URL]</p><p>This Privacy Policy should be read in conjunction with our [Terms of Use]([TERMS OF USE URL]) and [Community Guidelines]([COMMUNITY GUIDELINES URL]).</p><p>We will make every effort to respond to your inquiry in a timely manner.</p><hr><h2 id="placeholders-to-complete" tabindex="-1">Placeholders to Complete <a class="header-anchor" href="#placeholders-to-complete" aria-label="Permalink to &quot;Placeholders to Complete&quot;">​</a></h2><p>The following placeholders must be replaced with actual information before this Privacy Policy is published:</p><table tabindex="0"><thead><tr><th>Placeholder</th><th>Description</th></tr></thead><tbody><tr><td><code>[EFFECTIVE DATE]</code></td><td>The date this Privacy Policy takes effect</td></tr><tr><td><code>[COMPANY ADDRESS]</code></td><td>Registered business address of Yumina LLC</td></tr><tr><td><code>[CONTACT EMAIL]</code></td><td>Email address for privacy inquiries (e.g., <a href="mailto:privacy@yumina.com" target="_blank" rel="noreferrer">privacy@yumina.com</a>)</td></tr><tr><td><code>[WEBSITE URL]</code></td><td>Primary URL of the Yumina platform</td></tr><tr><td><code>[ANALYTICS PROVIDERS]</code></td><td>Names of analytics tools/providers once selected</td></tr><tr><td><code>[SECURITY EMAIL]</code></td><td>Security vulnerability reporting email</td></tr><tr><td><code>[TERMS OF USE URL]</code></td><td>URL to the Yumina Terms of Use</td></tr><tr><td><code>[COMMUNITY GUIDELINES URL]</code></td><td>URL to the Yumina Community Guidelines</td></tr><tr><td><code>[AI PROVIDERS URL]</code></td><td>URL to the current list of third-party AI providers</td></tr><tr><td><code>[DPO DESIGNATION OR STATEMENT]</code></td><td>Data Protection Officer designation or explanation</td></tr></tbody></table>',241)])])}const g=t(r,[["render",n]]);export{p as __pageData,g as default};
